<template>
	<view class="nav-bar flex-row" :style="{height: navBarHeight + 'px', justifyContent: algin, color: color}">
		<text class="title" :style="{bottom: titleBottom + 'px', width: calc(100% - menuInfo.width)}">{{title}}</text>
	</view>
</template>

<script>
	export default {
		name: "nav-bar",
		data() {
			return {
				navBarHeight: 0,
				titleBottom: 0,
				menuInfo: {}
			};
		},
		props: {
			title: String,
			algin: String,
			color: String
		},
		created() {
			const sysInfo = uni.getSystemInfoSync();
			const menuInfo = uni.getMenuButtonBoundingClientRect();
			this.menuInfo = menuInfo;

			this.navBarHeight = menuInfo.top * 2 + menuInfo.height - sysInfo.statusBarHeight;
			// console.log('导航栏高度：' + this.navBarHeight);

			this.titleBottom = menuInfo.top - sysInfo.statusBarHeight;
		}
	}
</script>

<style lang="scss" scoped>
	$nav-bar_padding: 10px;
	
	.nav-bar {
		width: 100%;
		background-color: $uni-color-primary;
		box-sizing: border-box;
		padding: 0 $nav-bar_padding;
		position: fixed;
		top: 0;

		.title {
			display: inline-block;
			position: absolute;
			width: calc(100% - $nav-bar_padding * 2);
			overflow-wrap: break-word;
		}
	}
</style>